import React, {createContext, useContext, useState, useEffect, type PropsWithChildren} from 'react';
import {Dimensions, type ScaledSize} from 'react-native';
import {createStyleContext, type StyleContext} from './helpers/style';

const StyleCtx = createContext<StyleContext>(createStyleContext());

/**
 * Subscribes to dimension changes (e.g. device rotation) so that
 * responsive values (portrait/landscape, phone/tablet, breakpoints)
 * update dynamically across the component tree.
 */
export function DimensionsProvider({children}: PropsWithChildren) {
    const [ctx, setCtx] = useState<StyleContext>(createStyleContext);

    useEffect(() => {
        const handler = ({window}: {window: ScaledSize}) => {
            setCtx(createStyleContext());
        };
        const subscription = Dimensions.addEventListener('change', handler);
        return () => subscription.remove();
    }, []);

    return (
        <StyleCtx.Provider value={ctx}>
            {children}
        </StyleCtx.Provider>
    );
}

/**
 * Returns the current style context (breakpoint, orientation, device, platform).
 * Re-renders when dimensions change (if DimensionsProvider is in the tree).
 */
export function useStyleContext(): StyleContext {
    return useContext(StyleCtx);
}
